import React, { useState } from 'react';

// --- RENK PALETİ VE STİLLER ---
const colors = {
  butterYellow: '#FEFAE0',
  softPink: '#F8AD9D',
  softBeige: '#FAEDCD',
  softGreen: '#B5E48C',
  white: '#FFFFFF',
  text: '#6B705C'
};

const commonStyles = {
  container: { backgroundColor: colors.butterYellow, minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: 'sans-serif', padding: '20px' },
  card: { backgroundColor: colors.white, width: '100%', maxWidth: '500px', padding: '40px', borderRadius: '40px', boxShadow: '0 15px 30px rgba(0,0,0,0.05)', textAlign: 'center' },
  input: { width: '100%', padding: '15px', marginBottom: '15px', borderRadius: '15px', border: `1px solid ${colors.softBeige}`, outline: 'none', boxSizing: 'border-box' },
  button: { width: '100%', padding: '15px', backgroundColor: colors.softPink, color: 'white', border: 'none', borderRadius: '15px', fontWeight: 'bold', cursor: 'pointer', marginTop: '20px' },
  tag: { padding: '10px 15px', borderRadius: '12px', border: `1px solid ${colors.softBeige}`, cursor: 'pointer', fontSize: '14px', transition: '0.3s' }
};

// --- 1. SAYFA: GİRİŞ & ÜYE OL ---
const AuthPage = ({ onNext }) => {
  const [isLogin, setIsLogin] = useState(true);
  return (
    <div style={commonStyles.container}>
      <div style={commonStyles.card}>
        <h1 style={{ color: colors.softPink, fontSize: '32px', marginBottom: '10px' }}>Planly 🌸</h1>
        <p style={{ color: '#A5A5A5', marginBottom: '30px' }}>{isLogin ? 'Tekrar hoş geldin!' : 'Yeni bir başlangıç yap!'}</p>

        {!isLogin && <input style={commonStyles.input} type="text" placeholder="Ad Soyad" />}
        <input style={commonStyles.input} type="email" placeholder="E-posta" />
        <input style={commonStyles.input} type="password" placeholder="Şifre" />

        <button style={commonStyles.button} onClick={onNext}>{isLogin ? 'Giriş Yap' : 'Kayıt Ol'}</button>

        <p style={{ marginTop: '20px', fontSize: '14px', color: '#A5A5A5' }}>
          {isLogin ? 'Hesabın yok mu?' : 'Zaten üye misin?'}
          <span onClick={() => setIsLogin(!isLogin)} style={{ color: colors.softPink, fontWeight: 'bold', marginLeft: '5px', cursor: 'pointer' }}>
            {isLogin ? 'Üye Ol' : 'Giriş Yap'}
          </span>
        </p>
      </div>
    </div>
  );
};

// --- 2. SAYFA: SINAV, DERS VE SAAT SEÇİMİ ---
const OnboardingPage = ({ onNext }) => {
  const [step, setStep] = useState('exam'); // exam -> subjects
  const [selectedExam, setSelectedExam] = useState('');
  const [selectedSubjects, setSelectedSubjects] = useState([]);
  const [hours, setHours] = useState(4);

  const examData = {
    'YKS': ['Matematik', 'Türkçe', 'Fizik', 'Kimya', 'Biyoloji', 'Tarih'],
    'KPSS': ['Genel Yetenek', 'Genel Kültür', 'Eğitim Bilimleri', 'Alan Bilgisi'],
    'DGS': ['Sayısal', 'Sözel'],
    'LGS': ['Fen Bilimleri', 'Matematik', 'İnkılap Tarihi']
  };

  const toggleSubject = (sub) => {
    setSelectedSubjects(prev => prev.includes(sub) ? prev.filter(s => s !== sub) : [...prev, sub]);
  };

  return (
    <div style={commonStyles.container}>
      <div style={commonStyles.card}>
        {step === 'exam' ? (
          <>
            <h2 style={{ color: colors.text }}>Hedefini Seç 🎯</h2>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px', marginTop: '20px' }}>
              {Object.keys(examData).map(exam => (
                <div key={exam} onClick={() => { setSelectedExam(exam); setStep('subjects'); }} 
                     style={{ ...commonStyles.tag, backgroundColor: selectedExam === exam ? colors.softPink : 'white', color: selectedExam === exam ? 'white' : colors.text, padding: '20px' }}>
                  {exam}
                </div>
              ))}
            </div>
          </>
        ) : (
          <>
            <h2 style={{ color: colors.text }}>{selectedExam} Derslerini Seç 📚</h2>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: '10px', justifyContent: 'center', marginTop: '20px' }}>
              {examData[selectedExam].map(sub => (
                <div key={sub} onClick={() => toggleSubject(sub)}
                     style={{ ...commonStyles.tag, backgroundColor: selectedSubjects.includes(sub) ? colors.softGreen : 'white', borderColor: colors.softGreen }}>
                  {sub}
                </div>
              ))}
            </div>

            <div style={{ marginTop: '30px' }}>
              <p style={{ fontWeight: 'bold', color: colors.text }}>Günlük Çalışma Saati: {hours} Saat</p>
              <input type="range" min="1" max="12" value={hours} onChange={(e) => setHours(e.target.value)} style={{ width: '100%', accentColor: colors.softPink }} />
            </div>

            <button style={commonStyles.button} onClick={onNext}>Programı Üret ✨</button>
            <p onClick={() => setStep('exam')} style={{ marginTop: '15px', fontSize: '12px', cursor: 'pointer', color: '#aaa' }}>← Sınavı Değiştir</p>
          </>
        )}
      </div>
    </div>
  );
};

// --- ANA UYGULAMA ---
function App() {
  const [page, setPage] = useState(1);

  return (
    <>
      {page === 1 && <AuthPage onNext={() => setPage(2)} />}
      {page === 2 && <OnboardingPage onNext={() => setPage(3)} />}
      {page === 3 && (
        <div style={commonStyles.container}>
          <div style={{ ...commonStyles.card, maxWidth: '800px' }}>
            <h2 style={{ color: colors.softPink }}>Programın Hazır! 🚀</h2>
            <p style={{ color: colors.text }}>Burada takvim ve arkadaşlarınla çalışma alanı olacak.</p>
            {/* 3. Sayfa (Dashboard) tasarımına bir sonraki adımda geçeceğiz */}
          </div>
        </div>
      )}
    </>
  );
}

export default App;
